sql:
SELECT channel_name
FROM channels
WHERE status = 'active';

SELECT COUNT(channel_id) AS total_channels
FROM channels
WHERE status = 'active';

SELECT channel_name, COUNT(channel_id) AS channel_count
FROM channels
GROUP BY channel_name;

